insert into public.work_steps (id, "order", label, description) values
  ('site_setup_safety', 1, 'Baustelle einrichten & schützen', 'Arbeitsbereich vorbereiten, Laufwege schützen, Strom/Wasser/Licht und persönliche Schutzausrüstung bereitstellen.'),
  ('substrate_inspection', 2, 'Untergrund prüfen', 'Flächen, Ebenheit, Saugfähigkeit und lose Schichten prüfen, bevor Material aufgetragen wird.'),
  ('substrate_cleaning', 3, 'Untergrund reinigen', 'Staub, Schmutz, Kleberreste und lose Bestandteile entfernen, damit Grundierung und Kleber haften.'),
  ('substrate_repair_leveling', 4, 'Untergrund ausbessern & ausgleichen', 'Kleine Fehlstellen, Risse und Unebenheiten mit fliesenrelevanten Spachtel- oder Ausgleichsmaterialien vorbereiten.'),
  ('priming', 5, 'Grundieren', 'Saugfähigkeit regulieren und Haftung für Abdichtung, Spachtelmasse oder Fliesenkleber verbessern.'),
  ('waterproofing', 6, 'Abdichten', 'Nassbereiche, Ecken, Anschlüsse, Durchdringungen und Abläufe fachgerecht abdichten.'),
  ('planning_layout', 7, 'Aufmaß & Verlegeplanung', 'Flächen, Zuschnitte, Fugenbild, Startachsen, Verschnitt und Profile planen.'),
  ('adhesive_mixing_application', 8, 'Fliesenkleber anmischen & auftragen', 'Fliesenkleber nach Herstellerangabe anmischen und mit passender Zahnung auftragen.'),
  ('cutting_drilling_edges', 9, 'Schneiden, Bohren & Kanten bearbeiten', 'Fliesen, Profile und Ausschnitte schneiden, Rohrdurchführungen bohren und Kanten nachbearbeiten.'),
  ('wall_tiling', 10, 'Wandfliesen verlegen', 'Wandfliesen ausrichten, setzen, nivellieren und Kanten sauber ausbilden.'),
  ('floor_tiling', 11, 'Bodenfliesen verlegen', 'Bodenfliesen hohlraumarm setzen, ausrichten, Randfugen freihalten und Flächen reinigen.'),
  ('profiles_baseboards_finishes', 12, 'Sockel, Profile & Abschlüsse', 'Sockelfliesen, Abschlussprofile, Übergänge, Türbereiche und Duschprofile herstellen.'),
  ('grouting', 13, 'Zementär verfugen', 'Fugen reinigen, Fugenmörtel anmischen, einarbeiten, waschen und nachreinigen.'),
  ('silicone_joints', 14, 'Silikon, Acryl & Wartungsfugen', 'Anschluss-, Eck- und Bewegungsfugen vorbereiten, hinterfüllen, abdichten und abziehen.'),
  ('final_cleaning_acceptance', 15, 'Endreinigung, Kontrolle & Dokumentation', 'Flächen reinigen, Qualität prüfen, Schichten dokumentieren und Reststoffe entsorgen.')
